    public static str concatInventSiteJoinUBSinventParametersSites(ItemId _itemId)
    {
        InventSum                inventSum;
        UBSInventParametersSites inventParametersSites;
        container con;

        while select InventSiteId from inventSum 
            exists join inventParametersSites
                group by inventSum.InventSiteId
                    where inventSum.ItemId == _itemId &&
                          inventSum.Closed == NoYes::No &&
                          inventSum.ClosedQty == NoYes::No &&
                          inventParametersSites.SiteId == inventSum.InventSiteId
        {
            con += inventSum.InventSiteId;
        }
                
        return con2Str(con,", ");
    }
